/* ── OS WINDOW MANAGER ───────────────────────────────────────────────────── */
var openWindows = {};
var dragState = null;
var resizeState = null;
var zTop = 20;

function openApp(name) {
  var win = document.getElementById('win-' + name);
  var tb = document.getElementById('tb-' + name);
  if (!win) return;
  win.classList.remove('minimized');
  win.style.display = 'flex';
  focusWindow(win);
  openWindows[name] = true;
  if (tb) { tb.classList.add('open'); tb.classList.add('active'); }
}

function closeApp(name) {
  var win = document.getElementById('win-' + name);
  var tb = document.getElementById('tb-' + name);
  if (win) { win.style.display = 'none'; win.classList.remove('focused'); }
  if (tb) { tb.classList.remove('open'); tb.classList.remove('active'); }
  delete openWindows[name];
}

function minimizeApp(name) {
  var win = document.getElementById('win-' + name);
  var tb = document.getElementById('tb-' + name);
  if (win) { win.classList.add('minimized'); win.classList.remove('focused'); }
  if (tb) { tb.classList.remove('active'); }
}

function maximizeApp(name) {
  var win = document.getElementById('win-' + name);
  if (!win) return;
  if (win.dataset.maximized === '1') {
    win.style.left = win.dataset.ox || '60px';
    win.style.top = win.dataset.oy || '30px';
    win.style.width = win.dataset.ow || '800px';
    win.style.height = win.dataset.oh || '600px';
    win.dataset.maximized = '0';
  } else {
    win.dataset.ox = win.style.left; win.dataset.oy = win.style.top;
    win.dataset.ow = win.style.width; win.dataset.oh = win.style.height;
    win.style.left = '0'; win.style.top = '0';
    win.style.width = '100vw'; win.style.height = 'calc(100vh - 56px)';
    win.dataset.maximized = '1';
  }
}

function focusWindow(win) {
  document.querySelectorAll('.os-window').forEach(function(w) { w.classList.remove('focused'); });
  win.classList.add('focused');
  zTop++;
  win.style.zIndex = zTop;
}

function dragStart(e, name) {
  var win = document.getElementById(name);
  focusWindow(win);
  if (win.dataset.maximized === '1') return;
  dragState = { name: name, sx: e.clientX, sy: e.clientY,
    ox: parseInt(win.style.left) || 0, oy: parseInt(win.style.top) || 0 };
  e.preventDefault();
}

document.addEventListener('mousemove', function(e) {
  if (dragState) {
    var win = document.getElementById(dragState.name);
    if (!win) return;
    var nx = dragState.ox + (e.clientX - dragState.sx);
    var ny = dragState.oy + (e.clientY - dragState.sy);
    ny = Math.max(0, ny);
    win.style.left = nx + 'px';
    win.style.top = ny + 'px';
  }
});

document.addEventListener('mouseup', function() {
  dragState = null;
});

// Click on desktop to unfocus
document.getElementById('desktop').addEventListener('mousedown', function(e) {
  if (e.target.id === 'desktop' || e.target.id === 'desktop-icons') {
    document.querySelectorAll('.os-window').forEach(function(w) { w.classList.remove('focused'); });
    document.querySelectorAll('.taskbar-app').forEach(function(t) { t.classList.remove('active'); });
  }
});

// Click window to focus
document.querySelectorAll('.os-window').forEach(function(win) {
  win.addEventListener('mousedown', function() { focusWindow(win); });
});

// Clock
function updateClock() {
  var now = new Date();
  var h = String(now.getHours()).padStart(2,'0');
  var m = String(now.getMinutes()).padStart(2,'0');
  var el = document.getElementById('taskbar-clock');
  if (el) el.textContent = h + ':' + m;
  var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  var de = document.getElementById('taskbar-date');
  if (de) de.textContent = months[now.getMonth()] + ' ' + now.getDate();
}
updateClock();
setInterval(updateClock, 10000);

function switchTab(t) { openApp(t); }

/* ── PASSWORD ────────────────────────────────────────────────────────────── */
const PW_HASH = '3c1ca2c74f7ca958362044d125a9ff54488e68978432622dfaaa09d7d76cde2c';

async function hashStr(str) {
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(str));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('');
}

async function checkPW() {
  const val = document.getElementById('pw-input').value;
  const h = await hashStr(val);
  if (h === PW_HASH) {
    document.getElementById('lock').style.display = 'none';
    sessionStorage.setItem('unlocked', '1');
  } else {
    const err = document.getElementById('lock-err');
    err.textContent = 'Incorrect password';
    document.getElementById('pw-input').value = '';
    document.getElementById('pw-input').style.borderColor = 'var(--accent4)';
    setTimeout(() => { err.textContent = ''; document.getElementById('pw-input').style.borderColor = ''; }, 2000);
  }
}

if (sessionStorage.getItem('unlocked') === '1') {
  document.getElementById('lock').style.display = 'none';
}
document.getElementById('pw-input').addEventListener('keydown', e => { if (e.key === 'Enter') checkPW(); });

/* ── FILE EDITOR ─────────────────────────────────────────────────────────── */
let feFiles = [], feActiveId = null, feNextId = 1, feArt = null, feEc = 0;

const FE_COLORS = {
  html:'#e34c26', css:'#264de4', js:'#f7df1e', json:'#6ee7b7',
  ts:'#3178c6', jsx:'#61dafb', tsx:'#3178c6', py:'#3572a5', md:'#888', txt:'#aaa'
};

function feExt(name) { const p = name.split('.'); return p.length > 1 ? p[p.length-1].toLowerCase() : 'txt'; }
function feColor(name) { return FE_COLORS[feExt(name)] || '#aaa'; }

function feLoad() {
  try {
    const s = JSON.parse(localStorage.getItem('fe_files'));
    if (s && s.length) { feFiles = s; feNextId = Math.max(...feFiles.map(f => f.id)) + 1; return true; }
  } catch(e) {}
  return false;
}

function feSave() {
  try { localStorage.setItem('fe_files', JSON.stringify(feFiles)); } catch(e) {}
}

function feInit() {
  if (!feLoad()) {
    feFiles = (window._FE_DEFAULTS || []).map(f => ({ id: feNextId++, name: f.name, content: atob(f.b64) }));
    if (!feFiles.length) feFiles = [{ id: feNextId++, name: 'index.html', content: '<!DOCTYPE html>\n<html>\n<body>\n<h1>Hello</h1>\n</body>\n</html>' }];
    feSave();
  }
  feActiveId = feFiles[0].id;
  feRenderSidebar(); feRenderTabs(); feOpenFile(feActiveId);
}

function feRenderSidebar() {
  const list = document.getElementById('fe-file-list');
  if (!list) return;
  list.innerHTML = feFiles.map(f =>
    '<div class="fe-file' + (f.id === feActiveId ? ' active' : '') + '" onclick="feOpenFile(' + f.id + ')">' +
    '<span class="fe-file-dot" style="background:' + feColor(f.name) + '"></span>' +
    '<span class="fe-file-name">' + f.name + '</span>' +
    '<span class="fe-file-del" onclick="feDelFile(event,' + f.id + ')">&#x2715;</span>' +
    '</div>'
  ).join('');
}

function feRenderTabs() {
  const bar = document.getElementById('fe-tabs');
  if (!bar) return;
  bar.innerHTML = feFiles.map(f =>
    '<div class="fe-tab' + (f.id === feActiveId ? ' active' : '') + '" onclick="feOpenFile(' + f.id + ')">' +
    '<span class="fe-tab-dot" style="background:' + feColor(f.name) + '"></span>' +
    f.name + '</div>'
  ).join('');
}

function feOpenFile(id) {
  const cur = feFiles.find(f => f.id === feActiveId);
  const ta = document.getElementById('ta-main');
  if (cur && ta) cur.content = ta.value;
  feActiveId = id;
  const f = feFiles.find(f => f.id === id);
  if (!f) return;
  if (ta) { ta.value = f.content || ''; feUpdateLines(); }
  feRenderSidebar(); feRenderTabs(); feSave();
  if (document.getElementById('autorun').checked) runCode();
}

function feUpdateLines() {
  const ta = document.getElementById('ta-main');
  const ln = document.getElementById('ln-main');
  if (!ta || !ln) return;
  const n = (ta.value.match(/\n/g) || []).length + 1;
  let h = '';
  for (let i = 1; i <= n; i++) h += '<span>' + i + '</span>';
  ln.innerHTML = h;
  ta.onscroll = () => { ln.scrollTop = ta.scrollTop; };
}

function feShowNew() {
  const r = document.getElementById('fe-new-row');
  const i = document.getElementById('fe-new-inp');
  if (r) r.style.display = 'flex';
  if (i) { i.value = ''; i.focus(); }
}
function feHideNew() { const r = document.getElementById('fe-new-row'); if (r) r.style.display = 'none'; }
function feNewKey(e) { if (e.key === 'Enter') feConfirmNew(); if (e.key === 'Escape') feHideNew(); }

function feConfirmNew() {
  const inp = document.getElementById('fe-new-inp');
  if (!inp) return;
  const name = inp.value.trim();
  if (!name) return;
  if (feFiles.find(f => f.name === name)) {
    inp.style.borderColor = 'var(--accent4)';
    setTimeout(() => inp.style.borderColor = '', 1500);
    return;
  }
  const f = { id: feNextId++, name, content: '' };
  feFiles.push(f); feSave(); feHideNew();
  feRenderSidebar(); feRenderTabs(); feOpenFile(f.id);
}

function feDelFile(e, id) {
  e.stopPropagation();
  if (feFiles.length <= 1) return;
  feFiles = feFiles.filter(f => f.id !== id);
  if (feActiveId === id) feActiveId = feFiles[0].id;
  feSave(); feRenderSidebar(); feRenderTabs(); feOpenFile(feActiveId);
}

function feDownload() {
  // Save current file content first
  const cur = feFiles.find(f => f.id === feActiveId);
  const ta = document.getElementById('ta-main');
  if (cur && ta) cur.content = ta.value;
  // Download ALL files one by one
  var mimeMap = { html:'text/html', css:'text/css', js:'application/javascript', json:'application/json' };
  var count = 0;
  feFiles.forEach(function(f, i) {
    setTimeout(function() {
      var ext = feExt(f.name);
      var mime = mimeMap[ext] || 'text/plain';
      // Strip path prefix for filename (e.g. public/index.html -> index.html)
      var fname = f.name.split('/').pop();
      dlF(f.content || '', fname, mime);
    }, i * 300); // stagger so browser doesn't block
    count++;
  });
  toast('Downloading ' + count + ' file' + (count !== 1 ? 's' : '') + '...');
}

function saveApp() {
  fetch(window.location.href)
    .then(function(r){ return r.blob(); })
    .then(function(blob){
      var u = URL.createObjectURL(blob);
      var a = document.createElement('a');
      a.href = u;
      a.download = 'devspace.html';
      a.style.display = 'none';
      document.body.appendChild(a);
      a.click();
      setTimeout(function(){ document.body.removeChild(a); URL.revokeObjectURL(u); }, 100);
      toast('Downloaded devspace.html!');
    }).catch(function(e){ toast('Error: ' + e.message); });
}

function onInput() {
  feUpdateLines();
  const cur = feFiles.find(f => f.id === feActiveId);
  const ta = document.getElementById('ta-main');
  if (cur && ta) { cur.content = ta.value; feSave(); }
  if (document.getElementById('autorun').checked) {
    clearTimeout(feArt); feArt = setTimeout(runCode, 600);
  }
}

function htab(e) {
  if (e.key === 'Tab') {
    e.preventDefault();
    const ta = e.target, s = ta.selectionStart;
    ta.value = ta.value.substring(0, s) + '  ' + ta.value.substring(ta.selectionEnd);
    ta.selectionStart = ta.selectionEnd = s + 2;
    feUpdateLines();
  }
}

/* ── RUN ─────────────────────────────────────────────────────────────────── */
function runCode() {
  clearConsole();
  const cur = feFiles.find(f => f.id === feActiveId);
  const ta = document.getElementById('ta-main');
  if (cur && ta) cur.content = ta.value;

  const hf = feFiles.find(f => feExt(f.name) === 'html');
  const cf = feFiles.find(f => feExt(f.name) === 'css');
  const jf = feFiles.find(f => feExt(f.name) === 'js');
  const h = hf ? hf.content : '', c = cf ? cf.content : '', j = jf ? jf.content : '';

  const fix = '<style>html,body{height:auto!important;overflow:auto!important}</style>';
  const ic = '<scr' + 'ipt>(function(){var _c=["log","warn","error","info","debug"];_c.forEach(function(m){var o=console[m].bind(console);console[m]=function(){var a=Array.prototype.slice.call(arguments),msg=a.map(function(x){try{return typeof x==="object"?JSON.stringify(x,null,2):String(x);}catch(e){return String(x);}}).join(" ");window.parent.postMessage({type:"console",method:m,message:msg},"*");o.apply(console,arguments);};});window.onerror=function(msg,s,l,c,err){window.parent.postMessage({type:"console",method:"error",message:(err?err.toString():msg)+(l?" (line "+l+")":"")},"*");};})();<' + '/sc' + 'ript>';

  let doc;
  if (h.indexOf('<html') >= 0 || h.indexOf('<!DOCTYPE') >= 0) {
    doc = h;
    doc = doc.indexOf('</head>') >= 0 ? doc.replace('</head>', fix + ic + '\n<style>' + c + '</style>\n</head>') : fix + ic + '<style>' + c + '</style>\n' + doc;
    const bs = '<scr' + 'ipt>' + j + '<' + '/sc' + 'ript>';
    doc = doc.indexOf('</body>') >= 0 ? doc.replace('</body>', bs + '\n</body>') : doc + bs;
  } else {
    doc = '<!DOCTYPE html><html><head><meta charset="UTF-8">' + fix + ic + '<style>' + c + '</style></head><body>' + h + '<scr' + 'ipt>' + j + '<' + '/sc' + 'ript></body></html>';
  }

  const blob = new Blob([doc], { type: 'text/html' });
  const bu = URL.createObjectURL(blob);
  const iframe = document.getElementById('preview');
  iframe.onload = () => URL.revokeObjectURL(bu);
  iframe.src = bu;
}

window.addEventListener('message', e => {
  if (!e.data || e.data.type !== 'console') return;
  addConsole(e.data.method, e.data.message);
});

function addConsole(m, msg) {
  const out = document.getElementById('cout');
  const em = out.querySelector('.cempty');
  if (em) em.remove();
  const icons = { log:'>', warn:'!', error:'x', info:'i', debug:'o' };
  const el = document.createElement('div');
  el.className = 'cline ' + (m === 'debug' ? 'log' : m);
  el.innerHTML = '<span class="cicon">' + (icons[m] || '>') + '</span><span>' + msg.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') + '</span>';
  out.appendChild(el); out.scrollTop = out.scrollHeight;
  if (m === 'error') { feEc++; const b = document.getElementById('eb'); b.textContent = feEc; b.classList.add('show'); }
}

function clearConsole() {
  feEc = 0;
  document.getElementById('eb').classList.remove('show');
  document.getElementById('cout').innerHTML = '<div class="cempty">Console output will appear here...</div>';
}

document.addEventListener('keydown', e => { if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') { e.preventDefault(); runCode(); } });

/* ── CLOAK (editor project → about:blank) ────────────────────────────────── */
function feCloak() {
  const cur = feFiles.find(f => f.id === feActiveId);
  const ta = document.getElementById('ta-main');
  if (cur && ta) cur.content = ta.value;
  const hf = feFiles.find(f => feExt(f.name) === 'html');
  const cf = feFiles.find(f => feExt(f.name) === 'css');
  const jf = feFiles.find(f => feExt(f.name) === 'js');
  const h = hf ? hf.content : '', c = cf ? cf.content : '', j = jf ? jf.content : '';
  let doc;
  if (h.indexOf('<html') >= 0 || h.indexOf('<!DOCTYPE') >= 0) {
    doc = h;
    doc = doc.indexOf('</head>') >= 0 ? doc.replace('</head>', '<style>' + c + '</style>\n</head>') : '<style>' + c + '</style>\n' + doc;
    const bs = '<scr' + 'ipt>' + j + '<' + '/sc' + 'ript>';
    doc = doc.indexOf('</body>') >= 0 ? doc.replace('</body>', bs + '\n</body>') : doc + bs;
  } else {
    doc = '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>' + c + '</style></head><body>' + h + '<scr' + 'ipt>' + j + '<' + '/sc' + 'ript></body></html>';
  }
  const t = window.open('about:blank', '_blank');
  if (!t) { toast('Popup blocked'); return; }
  t.document.open(); t.document.write(doc); t.document.close();
  toast('Opened in cloaked tab');
}

/* ── CLOAKERS PAGE ───────────────────────────────────────────────────────── */
function buildProxyPage(targetUrl) {
  var lines = [
    '<!DOCTYPE html><html><head><meta charset="UTF-8">',
    '<style>',
    '*{margin:0;padding:0;box-sizing:border-box}',
    'html,body{width:100%;height:100%;overflow:hidden;background:#0c0d10}',
    '#pbar{position:fixed;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,#5b8aff,#a78bfa);z-index:999;width:0%;transition:width .4s ease}',
    '#pnav{position:fixed;top:0;left:0;right:0;height:38px;background:rgba(12,13,16,0.96);backdrop-filter:blur(12px);border-bottom:1px solid rgba(255,255,255,0.07);display:flex;align-items:center;gap:8px;padding:0 12px;z-index:998;font-family:system-ui,sans-serif}',
    '#pback{background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.1);color:#e8eaf0;border-radius:6px;padding:4px 10px;font-size:11px;font-weight:600;cursor:pointer}',
    '#pback:hover{background:rgba(255,255,255,0.1)}',
    '#purl{flex:1;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.07);border-radius:6px;padding:4px 10px;font-size:11px;color:rgba(255,255,255,0.4);font-family:monospace;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}',
    '#pframe{position:fixed;inset:0;top:38px;border:none;width:100%;height:calc(100% - 38px)}',
    '</style></head><body>',
    '<div id="pbar"></div>',
    '<div id="pnav">',
    '  <button id="pback" onclick="goBack()">&#8592; Back</button>',
    '  <div id="purl">Loading...</div>',
    '</div>',
    '<iframe id="pframe" sandbox="allow-same-origin allow-scripts allow-popups allow-forms allow-top-navigation allow-modals allow-downloads"></iframe>',
  ];

  var scriptBody = [
    'var BASE=' + JSON.stringify(targetUrl) + ';',
    'var HIST=[];',
    'function enc(u){try{var b=btoa(unescape(encodeURIComponent(u))).replace(/\\+/g,"-").replace(/\\//g,"_").replace(/=/g,"");return"/proxy/"+b;}catch(e){return u;}}',
    'function absUrl(rel,base){try{return new URL(rel,base||BASE).href;}catch(e){return rel;}}',
    'function setBar(w){document.getElementById("pbar").style.width=w;}',
    'function loadUrl(target,pushHist){',
    '  if(pushHist!==false)HIST.push(BASE);',
    '  BASE=target;',
    '  document.getElementById("purl").textContent=target;',
    '  setBar("65%");',
    '  var f=document.getElementById("pframe");',
    '  f.onload=function(){setBar("100%");setTimeout(function(){setBar("0%");},400);};',
    '  f.src=enc(target);',
    '}',
    'function goBack(){if(HIST.length){loadUrl(HIST.pop(),false);}}',
    'document.getElementById("pframe").addEventListener("load",function(){',
    '  try{',
    '    var fd=this.contentDocument;if(!fd)return;',
    '    fd.addEventListener("click",function(ev){',
    '      var a=ev.target.closest("a");if(!a)return;',
    '      var href=a.href;',
    '      if(!href||href.startsWith("javascript:")||href.startsWith("mailto:"))return;',
    '      if(a.hasAttribute("download")||/\\.(pdf|zip|exe|dmg|apk|mp4|mp3|docx?|xlsx?|pptx?|png|jpg|gif|svg|csv|gz|tar|rar|7z)$/i.test(href)){',
    '        ev.preventDefault();',
    '        // Open download via the proxy server URL so browser can save it',
    '        var proxyHref=enc(absUrl(href,BASE));',
    '        window.open(proxyHref,"_blank");',
    '      } else if(!href.startsWith("#")){',
    '        ev.preventDefault();loadUrl(absUrl(href,BASE));',
    '      }',
    '    },true);',
    '  }catch(e){}',
    '});',
    'window.addEventListener("message",function(e){if(e.data&&e.data.type==="proxyNav"){loadUrl(absUrl(e.data.url));}});',
    'loadUrl(BASE,false);',
  ].join('\n');

  lines.push('<scr' + 'ipt>\n' + scriptBody + '\n</' + 'script>');
  lines.push('</body></html>');
  return lines.join('\n');
}

function setSt(dotId, stId, cls, msg) {
  var d = document.getElementById(dotId), s = document.getElementById(stId);
  if (!d || !s) return;
  d.className = 'csdot ' + cls;
  s.textContent = msg;
  if (cls === 'on') setTimeout(function() { d.className = 'csdot'; s.textContent = 'ready'; }, 3000);
}

function cpLaunchTab(inputId, dotId, stId) {
  var url = document.getElementById(inputId).value.trim() || 'https://google.com';
  var html = buildProxyPage(url);
  var t1 = window.open('about:blank', '_blank');
  if (!t1) { setSt(dotId, stId, 'err', 'popup blocked'); return; }
  t1.document.open(); t1.document.write(html); t1.document.close();
  var t2 = window.open('about:blank', '_blank');
  if (!t2) { setSt(dotId, stId, 'err', 'popup blocked'); return; }
  t2.document.open(); t2.document.write(html); t2.document.close();
  setSt(dotId, stId, 'on', 'launched 2 tabs');
}

function cpLaunchBlob(inputId, dotId, stId) {
  var url = document.getElementById(inputId).value.trim() || 'https://google.com';
  var html = buildProxyPage(url);
  var blob = new Blob([html], { type: 'text/html' });
  var bu = URL.createObjectURL(blob);
  var t = window.open(bu, '_blank');
  if (!t) { setSt(dotId, stId, 'err', 'popup blocked'); return; }
  setSt(dotId, stId, 'on', 'launched');
}

function cpDownload(inputId) {
  var url = document.getElementById(inputId).value.trim() || 'https://google.com';
  var name = prompt('Filename:', 'cloaked.html');
  if (!name) return;
  dlF(buildProxyPage(url), name, 'text/html');
  toast('Downloaded "' + name + '"');
}

/* ── UTILS ───────────────────────────────────────────────────────────────── */
function dlF(content, filename, mime) {
  var b = new Blob([content], { type: mime || 'text/plain' });
  var u = URL.createObjectURL(b);
  var a = document.createElement('a');
  a.href = u; a.download = filename; a.style.display = 'none';
  document.body.appendChild(a); a.click();
  setTimeout(function() { document.body.removeChild(a); URL.revokeObjectURL(u); }, 100);
}

function toast(msg) {
  var el = document.getElementById('toast');
  if (!el) return;
  el.textContent = msg; el.classList.add('show');
  setTimeout(function() { el.classList.remove('show'); }, 2500);
}


/* ── BROWSER ─────────────────────────────────────────────────────────────── */
var browserTabs = [];
var browserActiveTab = null;
var browserTabCounter = 0;

function browserEncode(u) {
  try {
    var b = btoa(unescape(encodeURIComponent(u))).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
    return '/proxy/' + b;
  } catch(e) { return u; }
}

function browserNormalize(raw) {
  raw = (raw || '').trim();
  if (!raw) return null;
  if (!raw.includes('.') || raw.includes(' ')) return 'https://www.google.com/search?q=' + encodeURIComponent(raw);
  if (!/^https?:\/\//i.test(raw)) raw = 'https://' + raw;
  return raw;
}

function browserNewTab(url) {
  var id = 'brtab' + (browserTabCounter++);
  var tab = { id: id, url: url || '', title: 'New Tab', hist: [], fwd: [] };
  browserTabs.push(tab);

  // Tab pill - use DOM methods to avoid quote escaping
  var tabbar = document.getElementById('browser-tabbar');
  var newBtn = tabbar.querySelector('.browser-new-tab-btn');
  var pill = document.createElement('div');
  pill.className = 'browser-tab';
  pill.id = 'pill-' + id;

  var titleSpan = document.createElement('span');
  titleSpan.className = 'browser-tab-title';
  titleSpan.id = 'title-' + id;
  titleSpan.textContent = 'New Tab';
  pill.appendChild(titleSpan);

  var closeSpan = document.createElement('span');
  closeSpan.className = 'browser-tab-close';
  closeSpan.textContent = '×';
  closeSpan.addEventListener('click', (function(tid){ return function(e){ browserCloseTab(e, tid); }; })(id));
  pill.appendChild(closeSpan);

  pill.addEventListener('click', (function(tid){ return function(e){ if (!e.target.classList.contains('browser-tab-close')) browserSwitchTab(tid); }; })(id));
  tabbar.insertBefore(pill, newBtn);

  // New tab page - use DOM methods
  var content = document.getElementById('browser-content');
  var page = document.createElement('div');
  page.className = 'browser-tab-page';
  page.id = 'page-' + id;

  var titleDiv = document.createElement('div');
  titleDiv.style.cssText = 'font-size:22px;font-weight:600;color:rgba(255,255,255,0.9);font-family:var(--font-ui)';
  titleDiv.textContent = 'DevSpace OS';
  page.appendChild(titleDiv);

  var searchBox = document.createElement('div');
  searchBox.style.cssText = 'width:100%;max-width:500px;background:#2b2b2b;border-radius:24px;padding:10px 20px;';
  var searchInp = document.createElement('input');
  searchInp.type = 'text';
  searchInp.placeholder = 'Search or type a URL';
  searchInp.autocomplete = 'off';
  searchInp.spellcheck = false;
  searchInp.style.cssText = 'width:100%;background:transparent;border:none;outline:none;color:rgba(255,255,255,0.9);font-size:14px;font-family:var(--font-ui);caret-color:white;';
  searchInp.addEventListener('keydown', (function(tid){ return function(e){ if(e.key==='Enter'){ var t=browserNormalize(e.target.value); if(t) browserTabNav(tid,t); } }; })(id));
  searchBox.appendChild(searchInp);
  page.appendChild(searchBox);

  var scGrid = document.createElement('div');
  scGrid.className = 'browser-sc-grid';
  var shortcuts = [
    {name:'Google',url:'https://google.com',color:'#1a73e8'},
    {name:'YouTube',url:'https://youtube.com',color:'#ff0000'},
    {name:'Reddit',url:'https://reddit.com',color:'#ff4500'},
    {name:'Twitter',url:'https://twitter.com',color:'#000000'},
    {name:'Discord',url:'https://discord.com',color:'#5865f2'},
    {name:'GitHub',url:'https://github.com',color:'#24292e'},
    {name:'Twitch',url:'https://twitch.tv',color:'#9147ff'},
    {name:'Wikipedia',url:'https://wikipedia.org',color:'#636363'},
  ];
  shortcuts.forEach(function(s) {
    var sc = document.createElement('div');
    sc.className = 'browser-sc';
    sc.addEventListener('click', (function(tid,u){ return function(){ browserTabNav(tid,u); }; })(id, s.url));
    var icon = document.createElement('div');
    icon.className = 'browser-sc-icon';
    icon.style.background = s.color;
    icon.textContent = s.name.substring(0,2).toUpperCase();
    var lbl = document.createElement('div');
    lbl.className = 'browser-sc-lbl';
    lbl.textContent = s.name;
    sc.appendChild(icon); sc.appendChild(lbl);
    scGrid.appendChild(sc);
  });
  page.appendChild(scGrid);
  content.appendChild(page);

  // Iframe
  var iframe = document.createElement('iframe');
  iframe.className = 'browser-tab-iframe';
  iframe.id = 'frame-' + id;
  content.appendChild(iframe);

  browserSwitchTab(id);
  if (url) browserTabNav(id, url);
  return id;
}


function browserSwitchTab(id) {
  // Deactivate all
  browserTabs.forEach(function(t) {
    var pill = document.getElementById('pill-' + t.id);
    var page = document.getElementById('page-' + t.id);
    var frame = document.getElementById('frame-' + t.id);
    if (pill) pill.classList.remove('active');
    if (page) page.classList.remove('active');
    if (frame) frame.classList.remove('active');
  });
  // Activate target
  browserActiveTab = id;
  var tab = browserTabs.find(function(t){ return t.id === id; });
  var pill = document.getElementById('pill-' + id);
  var page = document.getElementById('page-' + id);
  var frame = document.getElementById('frame-' + id);
  if (pill) pill.classList.add('active');
  var urlInput = document.getElementById('browser-url-input');
  if (tab) {
    if (urlInput) urlInput.value = tab.url || '';
    if (tab.url && frame) {
      page.classList.remove('active');
      frame.classList.add('active');
    } else {
      if (page) page.classList.add('active');
    }
  }
}

function browserTabNav(id, target) {
  var tab = browserTabs.find(function(t){ return t.id === id; });
  if (!tab) return;
  tab.url = target;
  tab.hist.push(target);
  tab.fwd = [];
  var titleEl = document.getElementById('title-' + id);
  if (titleEl) titleEl.textContent = target.replace(/^https?:\/\//, '').split('/')[0];
  var frame = document.getElementById('frame-' + id);
  var page = document.getElementById('page-' + id);
  if (frame) { frame.src = browserEncode(target); frame.classList.add('active'); }
  if (page) page.classList.remove('active');
  var urlInput = document.getElementById('browser-url-input');
  if (urlInput && id === browserActiveTab) urlInput.value = target;
}

function browserCloseTab(e, id) {
  e.stopPropagation();
  if (browserTabs.length <= 1) { browserNewTab(); }
  var idx = browserTabs.findIndex(function(t){ return t.id === id; });
  browserTabs.splice(idx, 1);
  var pill = document.getElementById('pill-' + id);
  var page = document.getElementById('page-' + id);
  var frame = document.getElementById('frame-' + id);
  if (pill) pill.remove();
  if (page) page.remove();
  if (frame) frame.remove();
  if (browserActiveTab === id) {
    var next = browserTabs[Math.min(idx, browserTabs.length - 1)];
    if (next) browserSwitchTab(next.id);
  }
}

function browserGo(e) {
  if (e && e.key !== 'Enter') return;
  var raw = document.getElementById('browser-url-input').value;
  var t = browserNormalize(raw);
  if (t && browserActiveTab) browserTabNav(browserActiveTab, t);
}

function browserNewtabGo(e, tabId) {
  if (e && e.key !== 'Enter') return;
  var raw = e.target.value;
  var t = browserNormalize(raw);
  if (t) browserTabNav(tabId, t);
}

function browserNavTo(target) {
  if (!browserActiveTab) browserNewTab(target);
  else browserTabNav(browserActiveTab, target);
}

function browserBack() {
  var tab = browserTabs.find(function(t){ return t.id === browserActiveTab; });
  if (!tab || tab.hist.length <= 1) return;
  tab.fwd.push(tab.hist.pop());
  var prev = tab.hist[tab.hist.length - 1];
  tab.url = prev;
  var frame = document.getElementById('frame-' + tab.id);
  var page = document.getElementById('page-' + tab.id);
  if (frame) { frame.src = browserEncode(prev); frame.classList.add('active'); }
  if (page) page.classList.remove('active');
  var urlInput = document.getElementById('browser-url-input');
  if (urlInput) urlInput.value = prev;
}

function browserFwd() {
  var tab = browserTabs.find(function(t){ return t.id === browserActiveTab; });
  if (!tab || !tab.fwd.length) return;
  var next = tab.fwd.pop();
  browserTabNav(tab.id, next);
}

function browserReload() {
  var tab = browserTabs.find(function(t){ return t.id === browserActiveTab; });
  if (!tab || !tab.url) return;
  var frame = document.getElementById('frame-' + tab.id);
  if (frame) { var s = frame.src; frame.src = 'about:blank'; setTimeout(function(){ frame.src = s; }, 50); }
}

// Init browser with one tab
function browserInit() {
  browserNewTab();
}


/* ── BOOT ────────────────────────────────────────────────────────────────── */
feInit();
